// COMPLETE, COMPILABLE C code
// Uses double precision and incremental clipping with circles.
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MAXV 1024
#define EPS 1e-9

typedef struct { double x, y; } Pt;

double sq(double x){return x*x;}

int inside(Pt p, Pt c){
    return sq(p.x - c.x) + sq(p.y - c.y) <= 1.0 + EPS;
}

// intersection of segment AB with unit circle centred at C (assumed to intersect)
void segment_circle_intersection(Pt a, Pt b, Pt c, Pt *out1, Pt *out2){
    // translate so that circle centre is at origin
    double ax = a.x - c.x, ay = a.y - c.y;
    double bx = b.x - c.x, by = b.y - c.y;
    double dx = bx - ax, dy = by - ay;
    double A = dx*dx + dy*dy;
    double B = 2*(ax*dx + ay*dy);
    double C = ax*ax + ay*ay - 1.0;
    double disc = B*B - 4*A*C;
    if(disc < 0) disc = 0;
    double sqrtD = sqrt(disc);
    double t1 = (-B - sqrtD) / (2*A);
    double t2 = (-B + sqrtD) / (2*A);
    if(t1 < -EPS) t1 = 0; if(t1 > 1+EPS) t1 = 1;
    if(t2 < -EPS) t2 = 0; if(t2 > 1+EPS) t2 = 1;
    out1->x = a.x + t1*dx; out1->y = a.y + t1*dy;
    out2->x = a.x + t2*dx; out2->y = a.y + t2*dy;
}

// Clip polygon (stored in arrays vx,vy, size *n) with unit disc centred at c.
// Result is stored back into the same arrays, new size returned.
int clip_with_disc(double *vx, double *vy, int n, Pt c){
    double nx[MAXV], ny[MAXV];
    int m = 0;
    if(n==0) return 0;
    for(int i=0;i<n;i++){
        Pt cur = {vx[i], vy[i]};
        Pt nxt = {vx[(i+1)%n], vy[(i+1)%n]};
        int curIn = inside(cur, c);
        int nxtIn = inside(nxt, c);
        if(curIn){
            nx[m] = cur.x; ny[m] = cur.y; m++;
        }
        if(curIn ^ nxtIn){
            Pt p1, p2;
            segment_circle_intersection(cur, nxt, c, &p1, &p2);
            // choose the intersection point that lies on the segment direction
            Pt inter = curIn ? p2 : p1;
            nx[m] = inter.x; ny[m] = inter.y; m++;
        }
        if(m >= MAXV-2) break; // safety
    }
    for(int i=0;i<m;i++){ vx[i]=nx[i]; vy[i]=ny[i]; }
    return m;
}

double polygon_area(double *vx, double *vy, int n){
    double a = 0.0;
    for(int i=0;i<n;i++){
        int j = (i+1)%n;
        a += vx[i]*vy[j] - vx[j]*vy[i];
    }
    return fabs(a)*0.5;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        Pt *cent = (Pt*)malloc(n*sizeof(Pt));
        for(int i=0;i<n;i++) scanf("%lf %lf", &cent[i].x, &cent[i].y);
        // initial big square
        double vx[MAXV], vy[MAXV];
        double L = 4000.0; // larger than any possible coordinate range
        vx[0] = -L; vy[0] = -L;
        vx[1] =  L; vy[1] = -L;
        vx[2] =  L; vy[2] =  L;
        vx[3] = -L; vy[3] =  L;
        int sz = 4;
        for(int i=0;i<n && sz>0;i++) sz = clip_with_disc(vx, vy, sz, cent[i]);
        double ans = (sz==0)?0.0:polygon_area(vx, vy, sz);
        printf("%.6f\n", ans);
        free(cent);
    }
    return 0;
}

